sys_script_include.script:
const NavigationManagerAJAX = Class.create();
NavigationManagerAJAX.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {
    getPageConfigs: function (page, params) {
        page = page || String(this.getParameter('page'));
        params = params || JSON.parse(String(this.getParameter('params')));

        const navManagerClient = new NavigationManager(page, params);
        const configs = navManagerClient.getConfigs();
        return JSON.stringify(configs);
    },
    type: 'NavigationManagerAJAX'
});
